import React, { useEffect, useState, useMemo } from "react";
import axios from "axios";
import { Bar, Pie } from "react-chartjs-2";
import "./AdminDashboard.css";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  ArcElement,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, ArcElement, Tooltip, Legend);

const AdminDashboard = () => {
  const [predictions, setPredictions] = useState([]);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axios.get("http://localhost:5000/admin/dashboard");
        setPredictions(res.data.predictions || []);
      } catch (err) {
        console.log("Error fetching data:", err);
      }
    };
    fetchData();
    const interval = setInterval(fetchData, 5000);
    return () => clearInterval(interval);
  }, []);

  const totalUsers = predictions.length;

  const salaries = useMemo(() => {
    return (Array.isArray(predictions) ? predictions : [])
      .map((p) => Number(String(p.salary || 0).replace(/,/g, "")))
      .filter((s) => !isNaN(s) && s > 0);
  }, [predictions]);

  const avgSalary = salaries.length ? salaries.reduce((a, b) => a + b, 0) / salaries.length : 0;
  const highestSalary = salaries.length ? Math.max(...salaries) : 0;
  const lowestSalary = salaries.length ? Math.min(...salaries) : 0;

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { position: "bottom", labels: { boxWidth: 10, font: { size: 11 } } },
    },
  };

  const handleLogout = () => {
    localStorage.removeItem("token");
    window.location.href = "/login";
  };

  return (
    <div className="admin-view">
      <aside className="sidebar-container">
        <div className="sidebar-profile">
          <div className="avatar">👤</div>
          <h3>Admin</h3>
        </div>
        <nav className="sidebar-nav">
          <div className="nav-link active">Dashboard</div>
          <div className="nav-link">Users</div>
          <div className="nav-link">Reports</div>
          <div className="nav-link">Settings</div>
        </nav>
        <button className="logout-btn" onClick={handleLogout}>Logout</button>
      </aside>

      <main className="content-area">
        <header className="content-header">
          <h2>Admin Dashboard</h2>
          <div className="header-icons">🔔 👤</div>
        </header>

        <div className="scrollable-content">
          {/* TOP CARDS SHOWING REAL VALUES */}
          <section className="stats-container">
            <div className="stat-item c1">
              <span>Avg. Salary</span>
              <h2>₹{avgSalary.toLocaleString(undefined, { maximumFractionDigits: 0 })}</h2>
            </div>
            <div className="stat-item c2">
              <span>Highest Salary</span>
              <h2>₹{highestSalary.toLocaleString()}</h2>
            </div>
            <div className="stat-item c3">
              <span>Lowest Salary</span>
              <h2>₹{lowestSalary.toLocaleString()}</h2>
            </div>
            <div className="stat-item c4">
              <span>Total Users</span>
              <h2>{totalUsers}</h2>
            </div>
          </section>

          <section className="charts-container">
            <div className="chart-card">
              <h4>Salary Distribution</h4>
              <div className="chart-box">
                <Bar 
                  data={{
                    labels: ["<40k", "40-60k", "60-80k", "80-100k", ">100k"],
                    datasets: [{ label: "Predictions", data: [12, 19, 3, 5, 2], backgroundColor: "#3b82f6" }]
                  }} 
                  options={chartOptions} 
                />
              </div>
            </div>
            <div className="chart-card">
              <h4>User Demographics</h4>
              <div className="chart-box">
                <Pie 
                  data={{
                    labels: ["Exp", "Entry", "Int", "Post"],
                    datasets: [{ data: [30, 20, 25, 25], backgroundColor: ["#6366f1", "#f59e0b", "#10b981", "#ef4444"] }]
                  }} 
                  options={chartOptions} 
                />
              </div>
            </div>
          </section>

          <section className="table-container">
            <h4>Recent Predictions</h4>
            <table className="custom-table">
              <thead>
                <tr><th>Email</th><th>Job Role</th><th>Location</th><th>Salary</th></tr>
              </thead>
              <tbody>
                {predictions.slice(-3).reverse().map((p, i) => (
                  <tr key={i}>
                    <td>{p.email}</td>
                    <td>{p.role}</td>
                    <td>{p.location}</td>
                    <td className="bold-price">₹{Number(String(p.salary || 0).replace(/,/g, "")).toLocaleString()}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </section>
        </div>
      </main>
    </div>
  );
};

export default AdminDashboard;
